package bio.problems

import bio.algorithms.analysis.SimilarMotifs
import bio.domain.analysis.SimilarMotifsProblem
import bio.domain.nucleic.DnaString
import cats.effect.IO

object KSIMProb {

  def solve(): IO[Unit] = {

    val k = 50

    val s = DnaString
      .from("".replace("\n", ""))
      .getOrElse(sys.error("invalid motif DNA string"))
    val t = DnaString
      .from("".replace("\n", ""))
      .getOrElse(sys.error("invalid genome DNA string"))

    val r = for {
      problem <- SimilarMotifsProblem.from(k, s, t)
      result = SimilarMotifs.findAll(problem)
    } yield result

    r match {
      case Left(err) =>
        IO.println(s"$err")
      case Right(hits) =>
        hits.foldLeft(IO.unit) { (acc, hit) =>
          acc *> IO.println(s"${hit.location} ${hit.length}")
        }
    }
  }
}
